1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Step = {
9	  op: string;
10	  items?: Item[];
11	};
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type ScenarioResult = {
19	  results: unknown[];
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	const LOYALTY_DISCOUNT = 0.2;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const CURSED_SURCHARGE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	
30	const ITEM_BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	const COMPONENT_BLOCK_SIZE = 3;
38	const COMPONENT_BLOCK_PREMIUM = 60;
39	
40	const groupCountsByType = (items: Item[]): Map<string, number> => {
41	  const counts = new Map<string, number>();
42	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
43	  return counts;
44	};
45	
46	const basePremiumForGroup = (type: string, count: number): number => {
47	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
48	  return count * ITEM_BASE_PREMIUM[type];
49	};
50	
51	const sumBasePremium = (counts: Map<string, number>): number => {
52	  let total = 0;
53	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
54	  return total;
55	};
56	
57	const isHighlyEnchanted = (item: Item): boolean =>
58	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
59	
60	const surchargeRateForItem = (item: Item): number =>
61	  (item.cursed ? CURSED_SURCHARGE : 0) +
62	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
63	
64	const surchargeForItem = (item: Item): number =>
65	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
66	
67	const itemSurcharges = (items: Item[]): number =>
68	  items.reduce((total, item) => total + surchargeForItem(item), 0);
69	
70	const calculatePremium = (items: Item[], yearsWithMHPCO: number): number => {
71	  const base = sumBasePremium(groupCountsByType(items));
72	  const surcharges = itemSurcharges(items);
73	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
74	  const loyalty = yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
75	  return Math.ceil(base + surcharges + firstInsurance - loyalty + PROCESSING_FEE);
76	};
77	
78	export const runScenario = (scenario: Scenario): ScenarioResult => {
79	  const results = scenario.steps.map((step) => ({
80	    premium: calculatePremium(step.items ?? [], scenario.customer.yearsWithMHPCO),
81	  }));
82	  return { results };
83	};
